function calculate({ snow_depth_in, snow_density_pcf, roof_pitch_deg, design_snow_load_psf, roof_dead_load_psf }) {
    // Input validation and default to 0 for non-positive values to prevent errors
    snow_depth_in = Math.max(0, parseFloat(snow_depth_in) || 0);
    snow_density_pcf = Math.max(0, parseFloat(snow_density_pcf) || 0);
    roof_pitch_deg = Math.max(0, parseFloat(roof_pitch_deg) || 0);
    design_snow_load_psf = Math.max(0, parseFloat(design_snow_load_psf) || 0);
    roof_dead_load_psf = Math.max(0, parseFloat(roof_dead_load_psf) || 0);

    // Step 1: Convert snow depth from inches to feet
    const snow_depth_ft = snow_depth_in / 12;

    // Step 2: Calculate the ground snow load (weight per horizontal square foot)
    const ground_snow_load_psf = snow_depth_ft * snow_density_pcf;

    // Step 3: Determine the roof slope factor (Cs) based on roof pitch
    // Using a simplified model based on ASCE 7-16 Figure 7.4-1 for cold roofs
    let Cs = 1.0; // Default for pitches <= 30 degrees
    if (roof_pitch_deg > 30 && roof_pitch_deg <= 70) {
        Cs = 1.0 - ((roof_pitch_deg - 30) / 40);
    } else if (roof_pitch_deg > 70) {
        Cs = 0.0; // Snow generally slides off roofs steeper than 70 degrees
    }
    Cs = Math.max(0, Cs); // Ensure Cs is not negative

    // Step 4: Calculate the effective vertical snow load on the roof
    const vertical_snow_load_psf = ground_snow_load_psf * Cs;

    // Step 5: Calculate the total roof load (effective snow load + roof dead load)
    const total_roof_load_psf = vertical_snow_load_psf + roof_dead_load_psf;

    // Step 6: Calculate the stress ratio
    let stress_ratio = 0;
    if (design_snow_load_psf > 0) {
        stress_ratio = (total_roof_load_psf / design_snow_load_psf) * 100;
    } else if (total_roof_load_psf > 0) {
        // If design capacity is 0 but there's actual load, it's an infinite risk
        stress_ratio = Infinity; 
    } else {
        // If both are 0, no load, no risk
        stress_ratio = 0;
    }

    // Step 7: Assess collapse risk
    let collapse_risk_assessment = "Low Risk";
    if (stress_ratio >= 70 && stress_ratio < 90) {
        collapse_risk_assessment = "Moderate Risk (Monitor, consider removal)";
    } else if (stress_ratio >= 90 && stress_ratio <= 100) {
        collapse_risk_assessment = "High Risk (Urgent removal recommended)";
    } else if (stress_ratio > 100) {
        collapse_risk_assessment = "CRITICAL Risk (Immediate removal, professional assessment needed, potential for imminent collapse)";
    } else if (stress_ratio === Infinity) {
        collapse_risk_assessment = "CRITICAL Risk (No design capacity or zero capacity specified)";
    }

    return {
        vertical_snow_load_psf,
        total_roof_load_psf,
        stress_ratio,
        collapse_risk_assessment
    };
}
